import pyautogui  # Библиотека для управления мышью, клавиатурой и поиска изображений на экране
import keyboard   # Библиотека для глобального отслеживания нажатий клавиш (например, 'Esc')
import time       # Библиотека для создания пауз (задержек) в скрипте
import random     # Библиотека для генерации случайных чисел (для имитации действий человека)

# Имя файла с картинкой, которую мы будем искать (должна лежать в той же папке, что и скрипт или .exe)
IMAGE_TO_FIND = 'template.png' 

def human_like_keypress(key):
    """
    Функция для имитации нажатия клавиши человеком.
    Добавляет небольшую случайную задержку перед нажатием.
    """
    # Генерируем случайную задержку от 0.1 до 0.3 секунд
    delay = random.uniform(0.1, 0.3)
    time.sleep(delay) # Ждем это случайное время
    pyautogui.press(key) # Нажимаем указанную клавишу
    print(f"Клавиша '{key}' нажата с задержкой {delay:.2f} сек.")

def main():
    print("Скрипт запущен. Для остановки нажмите и удерживайте клавишу 'Esc'.")
    
    # Бесконечный цикл, который работает, пока НЕ нажата клавиша 'Esc'
    while not keyboard.is_pressed('esc'):
        try:
            # Ищем центр изображения на экране. 
            # confidence=0.8 означает, что совпадение должно быть на 80% (помогает, если фон чуть изменился).
            # Для работы параметра confidence ОБЯЗАТЕЛЬНО нужен установленный opencv-python!
            location = pyautogui.locateCenterOnScreen(IMAGE_TO_FIND, confidence=0.8)
            
            # Если координаты найдены (изображение есть на экране)
            if location is not None:
                print(f"Изображение найдено на координатах: {location}")
                
                # Имитируем клик левой кнопкой мыши по найденным координатам
                pyautogui.click(location)
                print("Клик выполнен.")
                
                # Вызываем функцию случайного нажатия клавиши 'e'
                human_like_keypress('e')
                
                # Небольшая пауза после цикла действий, чтобы не перегружать систему
                time.sleep(1)
            else:
                # Если картинка не найдена, просто ждем немного и пробуем снова
                time.sleep(0.5)
                
        # Перехватываем исключение, если pyautogui вообще не может найти картинку 
        # (в новых версиях библиотеки при неудаче может вылетать ошибка ImageNotFoundException)
        except pyautogui.ImageNotFoundException:
            time.sleep(0.5)
        except Exception as e:
            print(f"Произошла ошибка: {e}")
            time.sleep(1)

    print("Скрипт остановлен пользователем.")

# Стандартная конструкция для запуска основной функции
if __name__ == "__main__":
    main()
